import { useEffect, useMemo, useState } from "react";
import api from "../../api/client";
import { exportRowsAsCsv, formatDate } from "../../utils/csv";

export default function HistoryTab() {
  const [items, setItems] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [query, setQuery] = useState("");
  const [skip, setSkip] = useState(0);
  const limit = 50;

  const load = async () => {
    setLoading(true);
    try {
      const response = await api.get("/user/validations", { params: { limit, skip } });
      setItems(response.data.validations || []);
      setTotal(response.data.total || 0);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, [skip]);

  const filtered = useMemo(() => items.filter((i) => i.email?.toLowerCase().includes(query.toLowerCase())), [items, query]);

  return (
    <div className="card space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <h3 className="text-lg font-semibold">History</h3>
        <button className="btn-outline" disabled={!filtered.length} onClick={() => exportRowsAsCsv("validation-history.csv", filtered)}>Export History as CSV</button>
      </div>

      <input className="input" placeholder="Search email..." value={query} onChange={(e) => setQuery(e.target.value)} />

      {loading ? (
        <p className="text-sm text-slate-500">Loading...</p>
      ) : (
        <div className="overflow-auto rounded border border-slate-200">
          <table className="min-w-full text-sm">
            <thead className="bg-slate-100">
              <tr>
                <th className="px-3 py-2 text-left">Email</th>
                <th className="px-3 py-2 text-left">Status</th>
                <th className="px-3 py-2 text-left">Cost</th>
                <th className="px-3 py-2 text-left">Date</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((row) => (
                <tr key={row._id} className="border-t border-slate-200">
                  <td className="px-3 py-2">{row.email}</td>
                  <td className="px-3 py-2">{row.isValid ? "?" : "?"}</td>
                  <td className="px-3 py-2">{row.creditCost}</td>
                  <td className="px-3 py-2">{formatDate(row.createdAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <div className="flex items-center justify-between text-sm">
        <span>Showing {skip + 1}-{Math.min(skip + limit, total)} of {total}</span>
        <div className="flex gap-2">
          <button className="btn-outline" disabled={skip === 0} onClick={() => setSkip(Math.max(skip - limit, 0))}>Prev</button>
          <button className="btn-outline" disabled={skip + limit >= total} onClick={() => setSkip(skip + limit)}>Next</button>
        </div>
      </div>
    </div>
  );
}
